BEGIN TRANSACTION;
CREATE TABLE suppliers (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	total_tonnes_committed FLOAT, 
	total_tonnes_delivered FLOAT, 
	transaction_count INTEGER, 
	geolocation_raw VARCHAR(100), 
	location_lat FLOAT, 
	location_lng FLOAT, 
	continent VARCHAR(100), 
	country VARCHAR(150), 
	city_region VARCHAR(255), 
	additional_locations TEXT, 
	technology VARCHAR(255), 
	certification VARCHAR(255), 
	price_per_tonne FLOAT, 
	biomass_source TEXT, 
	industrial_units INTEGER, 
	first_transaction VARCHAR(20), 
	last_transaction VARCHAR(20), 
	PRIMARY KEY (id)
);
CREATE TABLE transactions (
	id INTEGER NOT NULL, 
	announcement DATE, 
	year INTEGER, 
	tonnes FLOAT, 
	tonnes_delivered FLOAT, 
	method VARCHAR(255), 
	status VARCHAR(50), 
	marketplace VARCHAR(150), 
	registry_name VARCHAR(100), 
	purchaser VARCHAR(255), 
	notes TEXT, 
	source_file VARCHAR(255), 
	supplier_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(supplier_id) REFERENCES suppliers (id)
);
CREATE INDEX ix_suppliers_technology ON suppliers (technology);
CREATE INDEX ix_supplier_tech_continent ON suppliers (technology, continent);
CREATE INDEX ix_suppliers_continent ON suppliers (continent);
CREATE UNIQUE INDEX ix_suppliers_name ON suppliers (name);
CREATE INDEX ix_transactions_method ON transactions (method);
CREATE INDEX ix_transactions_supplier_id ON transactions (supplier_id);
CREATE INDEX ix_transactions_announcement ON transactions (announcement);
CREATE INDEX ix_transactions_registry_name ON transactions (registry_name);
CREATE INDEX ix_transactions_year ON transactions (year);
CREATE INDEX ix_transactions_status ON transactions (status);
CREATE INDEX ix_transactions_purchaser ON transactions (purchaser);
CREATE INDEX ix_tx_status_year ON transactions (status, year);
CREATE INDEX ix_tx_supplier_status ON transactions (supplier_id, status);
CREATE INDEX ix_tx_method_year ON transactions (method, year);
CREATE INDEX ix_transactions_marketplace ON transactions (marketplace);
CREATE INDEX ix_tx_marketplace ON transactions (marketplace);
COMMIT;
